        return 'No'
    s1, s2 = lst
    stack = []
    for char in s1:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if stack and stack[-1] == '(':
                stack.pop()
            else:
                return 'No'
    for char in s2:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if stack and stack[-1] == '(':
